sql:
SELECT tc.condition_name, e.engineer_name 
FROM test_conditions tc
INNER JOIN engineers e ON tc.created_by = e.engineer_id;

SELECT DISTINCT U.unit_name 
FROM units U 
JOIN test_results TR ON U.unit_id = TR.test_id;

SELECT e.engineer_id, e.engineer_name, e.email, e.department, e.phone_number, tr.test_id, tr.actual_value, tr.status, tr.test_group
FROM engineers e
INNER JOIN test_results tr ON e.engineer_id = tr.engineer_id;

external_knowledge:
- 'lunar cycle' metaphorically represents the month when the date-related changes occurred; 
- 'timekeepers' refers to both the test logs and test versions that keep track of changes and updates; 
- 'transformation' refers to the change date in the test_versions table;
- 'update narratives' refers to the updated_date in the test_logs table.

sql:
SELECT MAX(updated_date)
FROM test_versions
WHERE version_number > 2;

SELECT AVG(tr.actual_value) AS average_value
FROM test_results tr
WHERE tr.test_group = 'Batch 2' AND tr.test_id BETWEEN 10 AND 50;

SELECT * FROM test_conditions
ORDER BY updated_date DESC
LIMIT 1;

